krpano.action:
set(skin_settings.controlbar_visible, false);
set(skin_settings.thumbs_opened, false);

if(layer[skin_layer],
    set(layer[skin_layer].visible, false);
    set(layer[skin_layer].enabled, false);
    set(layer[skin_layer].alpha, 0);
    set(layer[skin_layer].height, 0);
);

if(layer[skin_control_bar],
    set(layer[skin_control_bar].visible, false);
    set(layer[skin_control_bar].enabled, false);
    set(layer[skin_control_bar].alpha, 0);
    set(layer[skin_control_bar].height, 0);
    set(layer[skin_control_bar].y, -1000);
);

if(layer[skin_splitter_bottom],
    set(layer[skin_splitter_bottom].visible, false);
    set(layer[skin_splitter_bottom].enabled, false);
    set(layer[skin_splitter_bottom].alpha, 0);
    set(layer[skin_splitter_bottom].height, 0);
    set(layer[skin_splitter_bottom].y, -1000);
);

if(layer[skin_scroll_window],
    set(layer[skin_scroll_window].visible, false);
    set(layer[skin_scroll_window].enabled, false);
    set(layer[skin_scroll_window].alpha, 0);
    set(layer[skin_scroll_window].height, 0);
    set(layer[skin_scroll_window].y, -1000);
);

if(layer[skin_btn_show],
    set(layer[skin_btn_show].visible, false);
    set(layer[skin_btn_show].enabled, false);
    set(layer[skin_btn_show].alpha, 0);
    set(layer[skin_btn_show].height, 0);
);

if(layer[skin_thumbs],
    set(layer[skin_thumbs].visible, false);
    set(layer[skin_thumbs].enabled, false);
    set(layer[skin_thumbs].alpha, 0);
    set(layer[skin_thumbs].height, 0);
);

if(layer[skin_map],
    set(layer[skin_map].visible, false);
    set(layer[skin_map].enabled, false);
    set(layer[skin_map].alpha, 0);
    set(layer[skin_map].height, 0);
);

s360_hide_skin();
delayedcall(0.10, s360_hide_skin(););
delayedcall(0.50, s360_hide_skin(););
js(window.js_initialize_suwon360());

s360_initialize();

delayedcall(0.20,
    s360_hide_skin();
    s360_scene_changed();
    s360_view_changed();
    s360_map_relayout();
);
